This implementation provides the skeleton of functions. Specific logic, especially for complex interaction like deleting a province based on mouse clicks, is simplified.

```cpp
#include "Province.hpp"
#include <fstream>
#include <sstream>

Province::Province() {}

Province::~Province() {}

void Province::drawProvince(Color fillColor, float strokeThickness, int strokeType) {
    for (const auto& province : provinces) {
        int pointsCount = static_cast<int>(province.size());
        if(pointsCount < 3) continue; // Ensure it's at least a triangle

        Vector2 pointsVec[pointsCount];
        for (int i = 0; i < pointsCount; i++) {
            pointsVec[i] = {static_cast<float>(province[i].x), static_cast<float>(province[i].y)};
        }

        // Fill Polygon
        DrawPolyEx(pointsVec, pointsCount, fillColor);

        // Stroke Polygon
        for (int i = 0; i < pointsCount; i++) {
            Vector2 start = pointsVec[i];
            Vector2 end = pointsVec[(i + 1) % pointsCount]; // Ensure closing the polygon
            if(strokeType == 0) { // Solid
                DrawLineEx(start, end, strokeThickness, BLACK);
            } else if(strokeType == 1) { // Dotted
                // Dotted line drawing might require custom implementation
            }
        }
    }
}

void Province::drawPoints() {
    // Placeholders for coordinates
    int x, y;
    while (!IsKeyPressed(KEY_ENTER)) {
        if (IsMouseButtonPressed(MOUSE_BUTTON_LEFT)) {
            Vector2 mousePos = GetMousePosition();
            x = static_cast<int>(mousePos.x);
            y = static_cast<int>(mousePos.y);
            points.push_back(Point{x, y});
        }
    }
    // Assuming you save after finishing
    provinces.push_back(points); // Add currently drawn points as a province
    points.clear(); // Clear current province points for next drawing
}

void Province::deletePoints() {
    if (!points.empty()) {
        points.pop_back();
    }
}

void Province::savePointsToFile(std::string filename) {
    std::ofstream outFile(filename, std::ios::app); // Appends to file
    if (outFile.is_open()) {
        for (const auto& province : provinces) {
            for (const auto& point : province) {
                outFile << point.x << ';';
            }
            outFile << "\n";
            for (const auto& point : province) {
                outFile << point.y << ';';
            }
            outFile << "\n";
        }
    }
    outFile.close();
}

bool Province::deleteProvince(Vector2 mousePoint) {
    // Simplified; should include logic to determine if point is inside a province's polygon and remove it.
    // This function just demonstrates a possible interface.
    return false;
}

void Province::loadProvincesFromFile(std::string filename) {
    std::ifstream inFile(filename);
    std::string lineX, lineY;
    while (std::getline(inFile, lineX) && std::getline(inFile, lineY)) {
        parseLineToPoints(lineX, lineY);
    }
}

void Province::parseLineToPoints(const std::string& lineX, const std::string& lineY) {
    std::vector<Point> newProvince;
    std::stringstream ssX(lineX), ssY(lineY);
    std::string itemX, itemY;

    while (getline(ssX, itemX, ';') && getline(ssY, itemY, ';')) {
        if (!itemX.empty() && !itemY.empty()) {
            Point newPoint{std::stoi(itemX), std::stoi(itemY)};
            newProvince.push_back(newPoint);
        }
    }

    provinces.push_back(newProvince);
}
```

### Key Simplifications & Assumptions:
- Real-time drawing is assumed to end when ENTER is pressed; user interaction is highly dependent on `raylib` functions like `IsKeyPressed` and `IsMouseButtonPressed`.
- The function `drawProvince` allows for basic rendering with options for filled color and stroke styles. The stroke style customization, especially for dotted lines, is left abstract since `raylib` doesn't natively support dotted lines; it requires a custom implementation.
- `deleteProvince` function notionally shows interface design - actual geometric computation (point-in-polygon test) is needed to determine if a mouse click is inside a province's area.
- File operations do not handle all edge cases; file formatting and error checking are minimal for clarity.
- This guide prioritizes demonstrating function interfaces and basic mechanics; it omits full error handling and complex geometry calculations for simplicity.

