void DrawPolyEx(const std::vector<Vector2>& points, Color fillColor, Color strokeColor, bool drawStroke) {
    if (points.size() < 3) return;

    for (size_t i = 1; i < points.size() - 1; i++) {
        DrawTriangle(points[0], points[i], points[i + 1], fillColor);
    }
    if (drawStroke) {
        for (size_t i = 0; i < points.size() - 1; i++) {
            DrawLineEx(points[i], points[i + 1], 2, strokeColor);
        }
        DrawLineEx(points.back(), points[0], 2, strokeColor);
    }
}

Province::Province() {
    std::vector<Vector2> points;
}

Province::~Province() {}
void Province::addPoint(int x, int y) {
    points.push_back({x, y}); // Добавление точки к временному хранению точек
}

void Province::drawProvince(Color fillColor, bool drawStroke, Color strokeColor, float strokeThickness) {
    for (const auto& province : provinces) {
        std::vector<Vector2> raylibPoints; // Преобразование точек Province::Point в Vector2 для Raylib

        for (const auto& point : province) {
            raylibPoints.push_back({static_cast<float>(point.x), static_cast<float>(point.y)});
        }

        // Заполнение полигона
        DrawPolyEx(raylibPoints, fillColor, strokeColor, drawStroke);

        // Если требуется рисовать контур
        if(drawStroke) {
            for(size_t i = 0; i < raylibPoints.size(); i++) {
                Vector2 start = raylibPoints[i];
                Vector2 end = raylibPoints[(i + 1) % raylibPoints.size()]; // Замыкание контура
                DrawLineEx(start, end, strokeThickness, strokeColor);
            }
        }
    }
}

void Province::drawPoints() {
    int x, y;
    while (!IsKeyPressed(KEY_ENTER)) {
        if (IsMouseButtonPressed(MOUSE_BUTTON_LEFT)) {
            Vector2 mousePos = GetMousePosition();
            x = static_cast<int>(mousePos.x);
            y = static_cast<int>(mousePos.y);

            // Добавление точки к вектору points
            Point newPoint = {x, y};
            points.push_back(newPoint);
        }
    }

    // Предполагается сохранение после завершения
    provinces.push_back(points); // Добавить текущие нарисованные точки как новую провинцию
    points.clear(); // Очистить текущие точки провинции для следующего рисования
}

void Province::deletePoints() {
    if (!points.empty()) {
        points.pop_back();
    }
}

void Province::savePointsToFile(std::string filename) {
    std::ofstream outFile(filename, std::ios::app); // Дозапись в файл
    if (outFile.is_open()) {
        for (const auto& province : provinces) {
            for (const auto& point : province) {
                outFile << point.x << ";" << point.y << '\n';
            }    
            outFile << '\n'; // Дополнительная пустая строка между провинциями
        }
    }
    outFile.close();
}

