void Province::loadProvincesFromFile(std::string filename) {
    std::ifstream inFile(filename);
    std::string lineX, lineY;
    while (std::getline(inFile, lineX) && std::getline(inFile, lineY)) {
        parseLineToPoints(lineX, lineY);
    }
}

void Province::parseLineToPoints(const std::string& lineX, const std::string& lineY) {
    std::vector<Point> newProvince;
    std::stringstream ssX(lineX), ssY(lineY);
    std::string itemX, itemY;

    while (getline(ssX, itemX, ';') && getline(ssY, itemY, ';')) {
        if (!itemX.empty() && !itemY.empty()) {
            Point newPoint {std::stoi(itemX), std::stoi(itemY)};
            newProvince.push_back(newPoint);
        }
    }

    provinces.push_back(newProvince);
}

